/**
 * Model for a dot menu option.
 * Represents an individual option in a dot menu with properties for label, icon, disabled state, and command action.
 * @example
 * const dotOptions = [
 *     {
 *         icon: 'fa fa-file-csv',
 *         label: this.translatePipe.transform('EXPORT_RESULT') + 'CSV',
 *         disabled: this.projects().length == 0,
 *         command: () => this.onExport('csv')
 *     },
 *     {
 *         icon: 'fa fa-file-excel',
 *         label: this.translatePipe.transform('EXPORT_RESULT') + 'Excel',
 *         disabled: this.projects().length == 0,
 *         command: () => this.onExport('xlsx')
 *     }
 * ];
 * @author Pascal Font
 */
export class IacDotMenuOption {
    constructor() {
        /**
         * Indicates whether the menu option is disabled.
         * @default false
         */
        this.disabled = false;
    }
}
